package log

import (
	"bytes"
	"runtime"

	"github.com/sirupsen/logrus"
)

// WindowsLineEndingFormatter wraps a logrus Formatter and normalizes line endings for Windows.
// On Windows, it converts \n to \r\n, but preserves existing \r\n sequences to avoid double-conversion.
type WindowsLineEndingFormatter struct {
	inner logrus.Formatter
}

// NewWindowsLineEndingFormatter creates a new formatter that normalizes line endings for Windows.
func NewWindowsLineEndingFormatter(inner logrus.Formatter) *WindowsLineEndingFormatter {
	return &WindowsLineEndingFormatter{
		inner: inner,
	}
}

// Format formats an entry and normalizes line endings on Windows.
func (f *WindowsLineEndingFormatter) Format(entry *logrus.Entry) ([]byte, error) {
	data, err := f.inner.Format(entry)
	if err != nil {
		return data, err
	}

	// Only normalize line endings on Windows
	if runtime.GOOS != "windows" {
		return data, nil
	}

	// Normalize line endings: replace \n with \r\n, but don't double-convert
	// existing \r\n sequences.
	// Strategy: replace \r\n with a placeholder, replace \n with \r\n, then
	// restore the placeholder (which is already \r\n)
	const placeholder = "\x00CRLF\x00"

	// First, temporarily replace \r\n with a placeholder
	data = bytes.ReplaceAll(data, []byte("\r\n"), []byte(placeholder))

	// Then, replace any remaining \n with \r\n
	data = bytes.ReplaceAll(data, []byte("\n"), []byte("\r\n"))

	// Finally, restore the placeholder (which is logically equivalent to \r\n)
	data = bytes.ReplaceAll(data, []byte(placeholder), []byte("\r\n"))

	return data, nil
}

package log

import (
	"testing"

	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"
	"github.com/sirupsen/logrus"
	"github.com/sirupsen/logrus/hooks/test"
)

func TestWindowsFormatter(t *testing.T) {
	RegisterFailHandler(Fail)
	RunSpecs(t, "Windows Formatter Suite")
}

var _ = Describe("WindowsLineEndingFormatter", func() {
	var formatter *WindowsLineEndingFormatter
	var innerFormatter logrus.Formatter

	BeforeEach(func() {
		innerFormatter = &logrus.TextFormatter{
			DisableColors:    true,
			DisableTimestamp: true,
			DisableSorting:   true,
		}
		formatter = NewWindowsLineEndingFormatter(innerFormatter)
	})

	Describe("Format", func() {
		It("converts single LF to CRLF on Windows", func() {
			entry := &logrus.Entry{
				Message: "test message",
				Level:   logrus.InfoLevel,
			}
			result, err := formatter.Format(entry)
			Expect(err).To(BeNil())
			Expect(result).NotTo(BeNil())

			// The actual formatting depends on the inner formatter, but we can
			// verify that the output ends with CRLF (since TextFormatter adds a newline)
			// Skip this validation if not on Windows - we'll test the normalization logic instead
		})

		It("preserves existing CRLF without double-conversion", func() {
			// Create a simple mock formatter that returns text with CRLF
			mockFormatter := &mockFormatter{output: "test\r\n"}
			windowsFormatter := NewWindowsLineEndingFormatter(mockFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			result, err := windowsFormatter.Format(entry)
			Expect(err).To(BeNil())

			// Should have exactly one CRLF, not double-converted to \r\r\n
			Expect(string(result)).To(Equal("test\r\n"))
		})

		It("converts multiple LF to CRLF", func() {
			mockFormatter := &mockFormatter{output: "line1\nline2\nline3\n"}
			windowsFormatter := NewWindowsLineEndingFormatter(mockFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			result, err := windowsFormatter.Format(entry)
			Expect(err).To(BeNil())
			Expect(string(result)).To(Equal("line1\r\nline2\r\nline3\r\n"))
		})

		It("handles mixed CRLF and LF correctly", func() {
			mockFormatter := &mockFormatter{output: "line1\r\nline2\nline3\r\nline4\n"}
			windowsFormatter := NewWindowsLineEndingFormatter(mockFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			result, err := windowsFormatter.Format(entry)
			Expect(err).To(BeNil())
			// All should be CRLF
			Expect(string(result)).To(Equal("line1\r\nline2\r\nline3\r\nline4\r\n"))
		})

		It("passes errors from inner formatter", func() {
			errorFormatter := &errorMockFormatter{}
			windowsFormatter := NewWindowsLineEndingFormatter(errorFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			_, err := windowsFormatter.Format(entry)
			Expect(err).NotTo(BeNil())
		})
	})
})

// Mock formatter for testing
type mockFormatter struct {
	output string
}

func (m *mockFormatter) Format(entry *logrus.Entry) ([]byte, error) {
	return []byte(m.output), nil
}

// Error mock formatter for testing error handling
type errorMockFormatter struct{}

func (m *errorMockFormatter) Format(entry *logrus.Entry) ([]byte, error) {
	return nil, ErrMockFormatterError
}

var ErrMockFormatterError = logrus.NewEntry(logrus.New()).WithError(nil).Logger.ReportCaller

