				Message: "test",
				Level:   logrus.InfoLevel,
			}

			result, err := windowsFormatter.Format(entry)
			Expect(err).To(BeNil())
			// The formatter only applies on Windows, so check based on runtime
			// For the test, we verify the logic works as expected
			outputStr := string(result)
			Expect(outputStr).To(ContainSubstring("line1"))
			Expect(outputStr).To(ContainSubstring("line2"))
			Expect(outputStr).To(ContainSubstring("line3"))
		})

		It("handles mixed CRLF and LF correctly", func() {
			mockFormatter := &mockFormatter{output: "line1\r\nline2\nline3\r\nline4\n"}
			windowsFormatter := NewWindowsLineEndingFormatter(mockFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			result, err := windowsFormatter.Format(entry)
			Expect(err).To(BeNil())
			outputStr := string(result)
			// Verify all lines are present
			Expect(outputStr).To(ContainSubstring("line1"))
			Expect(outputStr).To(ContainSubstring("line2"))
			Expect(outputStr).To(ContainSubstring("line3"))
			Expect(outputStr).To(ContainSubstring("line4"))
		})

		It("passes errors from inner formatter", func() {
			errorFormatter := &errorMockFormatter{shouldError: true}
			windowsFormatter := NewWindowsLineEndingFormatter(errorFormatter)

			entry := &logrus.Entry{
				Message: "test",
				Level:   logrus.InfoLevel,
			}

			_, err := windowsFormatter.Format(entry)
			Expect(err).NotTo(BeNil())
		})
	})
})

